    test_and_golden_context_ids: Object.freeze([...normalizedRequest.test_and_golden_context_ids]),
    golden_case_catalog_ref: normalizedRequest.golden_case_catalog_ref,
    unit_test_contract_ref: normalizedRequest.unit_test_contract_ref,
    tenant_boundary_precheck_applied: true,
    tenant_boundary_precheck_subphase_id: "RP00.P02.M07.S03",
    tenant_boundary_decision: precheckPassed ? "allow_metadata_only" : "deny_blocked_claim_required",
    precheck_passed: precheckPassed,
    blocked_claim_refs: uniqueFrozenStrings(blockedClaimRefs),
    required_evidence_refs: Object.freeze([...normalizedRequest.required_evidence_refs]),
    schema_expectation_fields: Object.freeze([...normalizedRequest.schema_expectation_fields]),
    acceptance_gate_ids: Object.freeze([...normalizedRequest.acceptance_gate_ids]),
    matter_trace_precheck_required: true,
    matter_trace_precheck_deferred_to: "RP00.P02.M07.S04",
