    service_entrypoint_contract_status: normalizedRequest.service_entrypoint_contract_status,
    claude_review_required_routing_closeout_ref: normalizedRequest.claude_review_required_routing_closeout_ref,
    claude_review_required_routing_closeout_status: normalizedRequest.claude_review_required_routing_closeout_status,
    review_required_routing_receipt_ref: normalizedRequest.review_required_routing_receipt_ref,
    command_evidence_ref: normalizedRequest.command_evidence_ref,
    tenant_boundary_precheck_applied: true,
    tenant_boundary_precheck_subphase_id: "RP00.P02.M05.S03",
    tenant_boundary_decision: precheckPassed ? "allow_metadata_only" : "deny_blocked_claim_required",
    precheck_passed: precheckPassed,
    blocked_claim_refs: uniqueFrozenStrings(blockedClaimRefs),
