function normalizeOptionalStateTransitionClaim(value, fallback, label) {
  if (value === undefined || value === null || value === false) return fallback;
  if (typeof value !== "string" || value.trim() === "" || value !== value.trim()) {
    throw new Error(`state transition enforcement ${label} must be a trimmed nonblank string`);
  }
  return value;
}

export function precheckControlPlaneAIImplementationHandoffStateTransitionEnforcement(
  secondaryWorkflowPathResult,
  stateTransitionClaims = {},
) {
  const policy = CONTROL_PLANE_AI_IMPLEMENTATION_HANDOFF_STATE_TRANSITION_ENFORCEMENT_POLICY;
  assertControlPlaneAIImplementationHandoffStateTransitionEnforcementPolicy(policy);
  if (
    !secondaryWorkflowPathResult
    || typeof secondaryWorkflowPathResult !== "object"
    || Array.isArray(secondaryWorkflowPathResult)
    || !secondaryWorkflowPathResult.secondary_workflow_receipt
    || typeof secondaryWorkflowPathResult.audit_event_ref !== "string"
    || secondaryWorkflowPathResult.audit_event_ref.trim() === ""
  ) {
    throw new Error("AI implementation handoff state transition enforcement requires S08 secondary workflow path result");
  }
  assertControlPlaneAIImplementationHandoffSecondaryWorkflowPathResult(secondaryWorkflowPathResult);
  if (secondaryWorkflowPathResult.secondary_workflow_path_decision !== "allow_metadata_only") {
    throw new Error("AI implementation handoff state transition enforcement requires carried allow_metadata_only secondary workflow path");
  }
  if (!stateTransitionClaims || typeof stateTransitionClaims !== "object" || Array.isArray(stateTransitionClaims)) {
    throw new Error("AI implementation handoff state transition enforcement claims must be an object");
  }
  const allowedClaimFields = new Set(["state_transition_from", "state_transition_to"]);
  for (const [claim, value] of Object.entries(stateTransitionClaims)) {
    if (allowedClaimFields.has(claim)) continue;
    if (value !== undefined && value !== null && value !== false) {
      if (policy.forbiddenStateTransitionClaims.includes(claim)) {
        throw new Error(`AI implementation handoff state transition enforcement rejects ${claim}`);
      }
      throw new Error(`AI implementation handoff state transition enforcement rejects unknown claim ${claim}`);
    }
  }
  const [allowedTransition] = policy.allowedStateTransitions;
  const stateTransitionFrom = normalizeOptionalStateTransitionClaim(
    stateTransitionClaims.state_transition_from,
    allowedTransition.from,
    "state_transition_from",
  );
  const stateTransitionTo = normalizeOptionalStateTransitionClaim(
    stateTransitionClaims.state_transition_to,
    allowedTransition.to,
    "state_transition_to",
  );
  if (stateTransitionFrom !== allowedTransition.from || stateTransitionTo !== allowedTransition.to) {
    throw new Error("AI implementation handoff state transition enforcement rejects invalid state transition");
  }
  const stateTransitionReceipt = Object.freeze({
    tenant_id: secondaryWorkflowPathResult.tenant_id,
    actor_id: secondaryWorkflowPathResult.actor_id,
    action_id: "ai_implementation_handoff.state_transition_enforcement",
    object_id: secondaryWorkflowPathResult.matter_id ?? "firm_level_ai_implementation_handoff",
    matter_id: secondaryWorkflowPathResult.matter_id,
    permission_decision_ref: secondaryWorkflowPathResult.permission_decision_ref,
    audit_event_ref: secondaryWorkflowPathResult.audit_event_ref,
    secondary_workflow_path_ref: "RP00.P02.M02.S08",
    secondary_workflow_path_behavior_ref: secondaryWorkflowPathResult.working_product_behavior_ref,
    state_transition_rule_ref: allowedTransition.ruleRef,
    state_transition_from: stateTransitionFrom,
    state_transition_to: stateTransitionTo,
    decision_reason: "s08_secondary_workflow_path_passed",
    working_product_behavior_ref: policy.workingProductBehaviorRef,
    effect: "allow_metadata_only",
    next_subphase: "RP00.P02.M02.S10",
  });
  const result = Object.freeze({
    entrypoint_id: "ai_implementation_handoff",
    tenant_id: secondaryWorkflowPathResult.tenant_id,
    actor_id: secondaryWorkflowPathResult.actor_id,
    actor_tenant_id: secondaryWorkflowPathResult.actor_tenant_id,
    resource_tenant_id: secondaryWorkflowPathResult.resource_tenant_id,
    matter_id: secondaryWorkflowPathResult.matter_id,
    matter_tenant_id: secondaryWorkflowPathResult.matter_tenant_id,
    permission_decision_ref: secondaryWorkflowPathResult.permission_decision_ref,
    audit_event_ref: secondaryWorkflowPathResult.audit_event_ref,
    ai_implementation_handoff_request_normalization_ref: secondaryWorkflowPathResult.ai_implementation_handoff_request_normalization_ref,
    tenant_boundary_precheck_ref: secondaryWorkflowPathResult.tenant_boundary_precheck_ref,
    matter_trace_precheck_ref: secondaryWorkflowPathResult.matter_trace_precheck_ref,
    permission_precheck_ref: secondaryWorkflowPathResult.permission_precheck_ref,
    audit_hint_precheck_ref: secondaryWorkflowPathResult.audit_hint_precheck_ref,
    primary_happy_path_ref: secondaryWorkflowPathResult.primary_happy_path_ref,
    secondary_workflow_path_ref: "RP00.P02.M02.S08",
    m00_request_normalization_ref: secondaryWorkflowPathResult.m00_request_normalization_ref,
    m00_tenant_boundary_precheck_ref: secondaryWorkflowPathResult.m00_tenant_boundary_precheck_ref,
    state_transition_enforcement_applied: true,
    state_transition_enforcement_subphase_id: "RP00.P02.M02.S09",
    state_transition_decision: "allow_metadata_only",
    state_transition_scope: "synthetic_control_plane_ai_implementation_handoff_state_transition_enforcement",
    state_transition_from: stateTransitionFrom,
    state_transition_to: stateTransitionTo,
    state_transition_rule_ref: allowedTransition.ruleRef,
    state_transition_receipt_fields: Object.freeze([...policy.requiredStateTransitionReceiptFields]),
    state_transition_receipt: stateTransitionReceipt,
    working_product_behavior_ref: policy.workingProductBehaviorRef,
    blocked_claim_refs: Object.freeze([]),
    handoff_context_ids: Object.freeze([...secondaryWorkflowPathResult.handoff_context_ids]),
    acceptance_gate_ids: Object.freeze([...secondaryWorkflowPathResult.acceptance_gate_ids]),
    implementation_handoff_drafted: false,
    service_logic_execution_permitted: false,
    runtime_route_created: false,
    permission_engine_execution_permitted: false,
    authz_evaluator_called: false,
    audit_ledger_write_permitted: false,
    audit_event_write_permitted: false,
    no_real_data: true,
    writes_product_state: false,
    next_subphase: "RP00.P02.M02.S10",
  });
  assertControlPlaneAIImplementationHandoffStateTransitionEnforcementResult(result);
  return result;
}

function normalizeOptionalSyntheticIdempotencyKey(value, fallback, label = "AI implementation handoff idempotency key handling") {
  if (value === undefined || value === null || value === false) {
    return { key: fallback, source: "default_synthetic_policy" };
  }
  if (typeof value !== "string" || value.trim() === "" || value !== value.trim()) {
    throw new Error(`${label} idempotency_key must be a trimmed nonblank string`);
  }
  if (!value.startsWith("idem.synthetic.")) {
    throw new Error(`${label} rejects non-synthetic idempotency_key`);
  }
  if (!/^idem\.synthetic\.[a-z0-9._:-]{1,113}$/.test(value)) {
    throw new Error(`${label} rejects invalid idempotency_key characters`);
  }
  if (value.length > 128) {
    throw new Error(`${label} rejects overlong idempotency_key`);
  }
  return { key: value, source: "explicit_synthetic_claim" };
}

